1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office — quote", () => {
5	  // Simplest case
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    expect(quote({ yearsWithMHPCO: 0 }, [], 0)).toBe(5);
8	  });
9	
10	  // Base premiums per item type (newcomer, no modifiers beyond first insurance & fee)
11	  it("single plain sword for newcomer (no prior contracts) → base 100 + 10 first + 5 fee = 115 G", () => {
12	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], 0)).toBe(115);
13	  });
14	  it.todo("single plain amulet for newcomer → base 60 + 6 first + 5 fee = 71 G");
15	  it.todo("single plain staff for newcomer → base 80 + 8 first + 5 fee = 93 G");
16	  it.todo("single plain potion for newcomer → base 40 + 4 first + 5 fee = 49 G");
17	
18	  // Components — base premiums (newcomer; verifying base before block rule)
19	  it.todo("2 runes → base 50 G (no block; +5 first +5 fee = 60 G)");
20	  it.todo("3 runes → base 60 G via block (+6 first +5 fee = 71 G)");
21	  it.todo("4 runes → base 100 G (no block; block requires exactly 3) → +10 first +5 fee = 115 G");
22	  it.todo("7 runes → base 175 G");
23	
24	  // "Alike" components clarification
25	  it.todo("2 runes + 1 moonstone → base 75 G (no block — different types)");
26	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
27	
28	  // Item-specific modifiers
29	  it.todo("cursed sword for newcomer → 100 + 50 curse + 10 first + 5 fee = 165 G");
30	  it.todo("sword with enchantment exactly 5 (newcomer) → 100 + 30 high-ench + 10 first + 5 fee = 145 G");
31	  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge → 115 G");
32	  it.todo("cursed sword with enchantment 5 (newcomer) → both surcharges apply");
33	
34	  // Modifier scope on multi-item policies (clarifying question ❓)
35	  it.todo("policy: cursed sword + plain amulet → 210 G before further modifiers and fee (newcomer additions extra)");
36	
37	  // Loyalty discount threshold
38	  it.todo("customer with exactly 2 years → loyalty discount applies (20% of policy base)");
39	  it.todo("customer with 1 year → no loyalty discount");
40	
41	  // Follow-up contract discount (each contract after the first → 15% off policy base)
42	  it.todo("second contract for same customer in same scenario → 15% follow-up discount applies");
43	
44	  // First insurance per item, regardless of customer history (❓ clarification)
45	  it.todo("long-standing customer's second contract: cursed sword ench 7 → premium 160 G (matches spec integration example)");
46	
47	  // Rounding in MHPCO's favor
48	  it.todo("premium calculation yielding 197.5 → final premium 198 (rounded up)");
49	
50	  // Errors
51	  it.todo("unknown item type in quote → throws error");
52	});
53	
54	describe("MHPCO Claim Office — claim", () => {
55	  // Standard reimbursement (no special clauses)
56	  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 − 100 deductible)");
57	  it.todo("rune (no enchantment / material), damage 200 → payout 100 (200 − 100 deductible)");
58	
59	  // Enchantment ≥8 clause
60	  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
61	
62	  // Dragon material clause
63	  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (full, then deductible)");
64	
65	  // Both clauses — 50% wins, then deductible
66	  it.todo("dragon-material sword ench 9, damage 1000 → payout 400");
67	  it.todo("dragon-material sword ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");
68	
69	  // Deductible per damage event
70	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");
71	
72	  // Multiple items of same type
73	  it.todo("policy with two swords; damage to both → each treated as separate damage with own deductible");
74	  it.todo("damages array has more entries of a type than the policy covers → throws error");
75	
76	  // Cap exhaustion
77	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
78	  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
79	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
80	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remaining 600; second claim 1500 → payout 600, remaining 0");
81	
82	  // Rounding for payouts
83	  it.todo("payout calculation yielding 350.5 → final payout 350 (rounded down)");
84	
85	  // Errors
86	  it.todo("claim references damage for an item not in the policy → throws error");
87	  it.todo("claim contains damage with negative amount → throws error");
88	});
